<template>
<div class="collections-container">
    <div class="preloader" v-if="items.length == 0"><b-spinner variant="primary" type="grow" label="Spinning"></b-spinner></div>
    <h1 class="main-title">
        <p>Коллекция</p>
        <span>весна-лето 2020-2021</span>
    </h1>
    <a v-for="item in items" v-bind:key="item.id" v-bind:data-title="item.name" class="collections-link" @click="detail(item.id)" v-bind:style="{ backgroundImage: 'url(' + item.picture + ')' }"></a>
</div>
</template>
<script>
export default {
    name: 'catalogSections',
    data: function(){
        return {
          items: []
        }
    },
    methods: {
        detail(id){
            this.$router.push('/catalog/'+id);
        },
        getItems(){
            let self = this;
            this.$store.dispatch('GET_COLLECTION_LIST')
            .then(data => {
                    self.items = data;
                })
            .catch(err => console.log(err));
        }
    },
    computed: {
        countItems: function () {
			return Object.keys(this.items).length;
		},
    },
    created(){
        this.getItems();
        
    },
    mounted() {
        // события при инициализации
        // this.getItems();
        this.fade = true
    }
}
</script>
<style lang="scss" scoped>
    .collections-container{
        width: 100%;
        .collections-link{
            display: flex;
            
        }
    }

</style>